  '[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is APS?","a":"Academic Evaluation Centre verification for Indian academic documents—mandatory for most Indian student visa applicants."},{"q":"Proof of funds amount for 2026?","a":"Typically required living funds (12 months × €992). Verify current amount before opening account."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need Portuguese?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Ausländerbehörde soon after arrival and registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Portuguesey."},{"q":"What after graduation?","a":"Discuss 18-month job-seeker residence permit or Opportunity Card separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised Portuguese university or preparatory course. After entry, convert to residence permit at local Ausländerbehörde."},{"q":"What is Eligible applicants for this service?","a":"University admission (Zulassung) or conditional admission · Proof of funds or scholarship · admission documentation (India) · Health insurance · Motivation letter"},{"q":"What is Proof of funds for this service?","a":"required living funds for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Proof of funds?","a":"required living funds for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"Portuguese Embassy/Consulate in India · Federal Foreign Office · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Portuguesey; register address; apply for residence permit at Ausländerbehörde within visa validity."},{"q":"Is Admission from recognised Portuguese institution required?","a":"Admission from recognised Portuguese institution is typically required."},{"q":"Is admission documentation (India) required?","a":"Apply early—processing takes weeks"},{"q":"Is Proof of funds or financial proof required?","a":"required living funds for 2026 or equivalent"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"Portuguese or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file + APS"},{"q":"What is the Government fee?","a":"€75 — + proof of funds required living funds"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + APS & proof of funds"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has APS not completed?","a":"Complete APS before embassy slot; track processing on APS website"},{"q":"Why is APS not completed a problem?","a":"Visa appointment booked without admission documentation."},{"q":"What if the client has Insufficient proof of funds?","a":"Open proof of funds at approved bank for full required amount"},{"q":"Why is Insufficient proof of funds a problem?","a":"Amount below required monthly sum or not from recognised provider."}]'::jsonb
), updated_at = now()
